6.2 Verificação rápida do ambiente
Use este bloco para diagnóstico rápido:

# Verificar versão do R
R.version.string

# Verificar pacotes instalados e suas versões
pacotes_check &lt;- c("terra", "sf", "landscapemetrics", "tmap", "vegan", "tidyverse")

for (pkg in pacotes_check) {
  if (requireNamespace(pkg, quietly = TRUE)) {
    v &lt;- packageVersion(pkg)
    cat(sprintf("✓ %-20s versão %s\n", pkg, v))
  } else {
    cat(sprintf("✗ %-20s NÃO instalado\n", pkg))
  }
}

7.4 Matriz de correlação entre métricas


Código
# Calcular conjunto amplo de métricas na paisagem exemplo
todas &lt;- calculate_lsm(
  paisagem,
  what = c(
    "lsm_c_pland", "lsm_c_np", "lsm_c_ed",
    "lsm_c_ai",    "lsm_c_enn_mn", "lsm_c_shape_mn",
    "lsm_c_lpi",   "lsm_c_pd",    "lsm_c_frac_mn",
    "lsm_c_cohesion"
  )
) |&gt;
  filter(level == "class") |&gt;
  select(class, metric, value) |&gt;
  pivot_wider(names_from = metric, values_from = value, values_fn = mean) |&gt;
  select(-class)

# Correlação
if (ncol(todas) &gt;= 4) {
  cor_mat &lt;- cor(todas, use = "pairwise.complete.obs")

  # Visualizar com corrplot (se disponível) ou heatmap simples
  if (requireNamespace("corrplot", quietly = TRUE)) {
    corrplot::corrplot(cor_mat, method = "color",
                       tl.cex = 0.8, number.cex = 0.7,
                       addCoef.col = "black", type = "upper",
                       col = colorRampPalette(c("#A32D2D","white","#27500A"))(200),
                       title = "Correlação entre métricas (classe)",
                       mar = c(0,0,1,0))
  } else {
    # Alternativa: heatmap com ggplot2
    cor_df &lt;- as.data.frame(cor_mat) |&gt;
      tibble::rownames_to_column("m1") |&gt;
      pivot_longer(-m1, names_to = "m2", values_to = "r")

    ggplot(cor_df, aes(x = m1, y = m2, fill = r)) +
      geom_tile(color = "white") +
      scale_fill_gradient2(
        low = "#A32D2D", mid = "white", high = "#27500A",
        midpoint = 0, limits = c(-1, 1),
        name = "r de\nPearson"
      ) +
      geom_text(aes(label = round(r, 2)), size = 2.8) +
      labs(title = "Matriz de correlação entre métricas de paisagem",
           x = NULL, y = NULL) +
      theme_minimal(base_size = 11) +
      theme(axis.text.x = element_text(angle = 45, hjust = 1))
  }
}





