9.2 Visualizando borda como proxy de fluxo lateral


Código
borda_classe &lt;- metricas_fluxo |&gt;
  filter(metric == "ed", level == "class") |&gt;
  mutate(
    classe = case_when(
      class == 1 ~ "Floresta",
      class == 2 ~ "Agricultura",
      class == 3 ~ "Outros"
    ),
    interpretacao = case_when(
      class == 1 ~ "Alta retenção\nde nutrientes",
      class == 2 ~ "Alta exportação\nde N e P",
      class == 3 ~ "Variável"
    )
  )

ggplot(borda_classe, aes(x = classe, y = value, fill = classe)) +
  geom_col(alpha = 0.85, width = 0.6) +
  geom_text(aes(label = paste0(round(value, 1), " m/ha\n", interpretacao)),
            vjust = -0.3, size = 3.2, color = "#1a1a18") +
  scale_fill_manual(values = c(
    "Floresta"    = "#27500A",
    "Agricultura" = "#BA7517",
    "Outros"      = "#378ADD"
  )) +
  scale_y_continuous(expand = expansion(mult = c(0, 0.3))) +
  labs(
    title    = "Densidade de borda por classe de uso do solo",
    subtitle = "Proxy para intensidade de fluxos laterais de nutrientes",
    x        = NULL,
    y        = "Densidade de borda (m/ha)",
    caption  = "Fonte: landscapemetrics::landscape"
  ) +
  theme_classic(base_size = 12) +
  theme(legend.position = "none")





Densidade de borda por classe — quanto maior a borda, maior o potencial de fluxo lateral entre patches

Escrevendo suas próprias funções
Você pode criar suas próprias funções usando a função function().
Estrutura básica:

nome_da_funcao &lt;- function(argumentos) {
  # código
  return(resultado)
}


Exemplo simples

square &lt;- function(x) {
  x^2
}

square(4)

[1] 16




Função com múltiplos argumentos

power &lt;- function(base, exponent = 2) {
  base^exponent
}

power(3)

[1] 9

power(3, 3)

[1] 27
